#include<bits/stdc++.h>
using namespace std;
int n,s,dis[310],f[310];
int p[310],sum[310],cnt,max1;
bool vis[310];
vector<pair<int,int>> mp[310];
void dfs(int x,int fa=0)
{
    f[x]=fa;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!vis[v])
        {
            dis[v]=dis[x]+val;
            if(dis[v]>dis[max1])
            {
                max1=v;
            }
            dfs(v,x);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&s);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(1);
    dis[max1]=0;
    dfs(max1);
    int x=max1;
    while(x)
    {
        p[++cnt]=x;
        sum[cnt]=dis[x];
        x=f[x];
    }
    reverse(p+1,p+1+cnt);
    reverse(sum+1,sum+1+cnt);
    int ans=INT_MAX;
    for(int i=1;i<=cnt;i++)
    {
        for(int j=i;j<=cnt;j++)
        {
            if(sum[j]-sum[i]<=s)
            {
                memset(vis,0,sizeof(vis));
                for(int k=i;k<=j;k++)
                {
                    vis[p[k]]=true;
                }
                int res=0;
                for(int k=i;k<=j;k++)
                {
                    dis[p[k]]=0;
                    max1=0;
                    dfs(p[k]);
                    res=max(res,dis[max1]);
                }
                ans=min(ans,res);
            }
        }
    }
    printf("%d",ans);
    return 0;
}
